/**
 * Create a WebGPU "bind group" from an array of luma.gl bindings
 */
export function getBindGroup(device, bindGroupLayout, shaderLayout, bindings) {
    const entries = getBindGroupEntries(bindings, shaderLayout);
    device.pushErrorScope('validation');
    const bindGroup = device.createBindGroup({
        layout: bindGroupLayout,
        entries
    });
    device.popErrorScope().then((error) => {
        if (error) {
            log.error(`bindGroup creation: ${error.message}`, bindGroup)();
        }
    });
    return bindGroup;
}
export function getShaderLayoutBinding(shaderLayout, bindingName, options) {
    const bindingLayout = shaderLayout.bindings.find(binding => binding.name === bindingName ||
        `${binding.name.toLocaleLowerCase()}uniforms` === bindingName.toLocaleLowerCase());
    if (!bindingLayout && !options?.ignoreWarnings) {
        log.warn(`Binding ${bindingName} not set: Not found in shader layout.`)();
    }
    return bindingLayout || null;
}
/**
 * @param bindings
 * @returns
 */
function getBindGroupEntries(bindings, shaderLayout) {
    const entries = [];
    for (const [bindingName, value] of Object.entries(bindings)) {
        const exactBindingLayout = shaderLayout.bindings.find(binding => binding.name === bindingName);
        let bindingLayout = exactBindingLayout || getShaderLayoutBinding(shaderLayout, bindingName);
        // Mirror the WebGL path: when both `foo` and `fooUniforms` exist in the bindings map,
        // prefer the exact shader binding name and ignore the alias entry.
        if (!exactBindingLayout && bindingLayout && bindingLayout.name in bindings) {
            continue;
        }
        if (bindingLayout) {
            const entry = getBindGroupEntry(value, bindingLayout.location, undefined, bindingName);
            if (entry) {
                entries.push(entry);
            }
        }
        // TODO - hack to automatically bind samplers to supplied texture default samplers
        if (value instanceof Texture) {
            bindingLayout = getShaderLayoutBinding(shaderLayout, `${bindingName}Sampler`, {
                ignoreWarnings: true
            });
            if (bindingLayout) {
                const entry = getBindGroupEntry(value, bindingLayout.location, { sampler: true }, bindingName);
                if (entry) {
                    entries.push(entry);
                }
            }
        }
    }
    return entries;
}
function getBindGroupEntry(binding, index, options, bindingName = 'unknown') {
    if (binding instanceof Buffer) {
        return {
            binding: index,
            resource: {
                buffer: binding.handle
            }
        };
    }
    if (binding instanceof Sampler) {
        return {
            binding: index,
            resource: binding.handle
        };
    }
    if (binding instanceof TextureView) {
        return {
            binding: index,
            resource: binding.handle
        };
    }
    if (binding instanceof Texture) {
        if (options?.sampler) {
            return {
                binding: index,
                resource: binding.sampler.handle
            };
        }
        return {
            binding: index,
            resource: binding.view.handle
        };
    }
    log.warn(`invalid binding ${bindingName}`, binding);
    return null;
}
